import { useState } from "react";
import axios from "axios";

function AuthPage({ onNext }) {
  const [mode, setMode] = useState("login"); // "login" | "register"

  const [username, setUsername] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");

  const handleRegister = async () => {
    setError("");
    try {
      await axios.post("http://localhost:5001/api/auth/register", {
        username,
        email,
        password,
      });
      onNext();
    } catch (e) {
      const message = e?.response?.data?.message || "Kayıt başarısız";
      setError(message);
    }
  };

  const handleLogin = async () => {
    setError("");
    try {
      await axios.post("http://localhost:5001/api/auth/login", {
        email,
        password,
      });
      onNext();
    } catch (e) {
      const message = e?.response?.data?.message || "Giriş başarısız";
      setError(message);
    }
  };

  return (
    <div>
      <h2>{mode === "login" ? "Giriş" : "Kayıt Ol"}</h2>

      {mode === "register" && (
        <div>
          <input
            placeholder="Kullanıcı adı"
            value={username}
            onChange={(e) => setUsername(e.target.value)}
          />
        </div>
      )}

      <div>
        <input
          placeholder="E-posta"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />
      </div>

      <div>
        <input
          type="password"
          placeholder="Şifre"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />
      </div>

      {error && <p style={{ color: "crimson" }}>{error}</p>}

      <div>
        {mode === "login" ? (
          <button onClick={handleLogin} disabled={!email || !password}>
            Giriş Yap
          </button>
        ) : (
          <button
            onClick={handleRegister}
            disabled={!username || !email || !password}
          >
            Kayıt Ol
          </button>
        )}
      </div>

      <div>
        {mode === "login" ? (
          <button onClick={() => setMode("register")}>Kayıt ol</button>
        ) : (
          <button onClick={() => setMode("login")}>Girişe dön</button>
        )}
      </div>
    </div>
  );
}

export default AuthPage;
